// Types
export interface Product {
  productId: string;
  title: string;
  description: string;
  price: string;
  currency: string;
  localizedPrice: string;
  type: 'inapp' | 'subscription';
}

export interface Transaction {
  id: string;
  productId: string;
  amount: number;
  currency: string;
  status: 'pending' | 'completed' | 'failed' | 'refunded' | 'cancelled';
  provider: 'apple' | 'google' | 'stripe' | 'wallet';
  receipt?: string;
  timestamp: number;
  metadata?: Record<string, any>;
  idempotencyKey: string;
}

export interface WalletInfo {
  id: string;
  balance: number;
  currency: string;
  lastUpdated: number;
  cards: PaymentCard[];
}

export interface PaymentCard {
  id: string;
  last4: string;
  brand: 'visa' | 'mastercard' | 'amex' | 'discover';
  expiryMonth: number;
  expiryYear: number;
  isDefault: boolean;
  tokenizedId: string;
}

export interface PaymentState {
  products: Product[];
  transactions: Transaction[];
  wallet: WalletInfo | null;
  isLoading: boolean;
  isInitialized: boolean;
  error: string | null;
  pendingPurchase: string | null;
}

type PaymentAction =
  | { type: 'SET_LOADING'; payload: boolean }
  | { type: 'SET_INITIALIZED'; payload: boolean }
  | { type: 'SET_PRODUCTS'; payload: Product[] }
  | { type: 'ADD_TRANSACTION'; payload: Transaction }
  | { type: 'UPDATE_TRANSACTION'; payload: { id: string; updates: Partial<Transaction> } }
  | { type: 'SET_WALLET'; payload: WalletInfo }
  | { type: 'SET_ERROR'; payload: string | null }
  | { type: 'SET_PENDING_PURCHASE'; payload: string | null }
  | { type: 'CLEAR_ERROR' };

const initialState: PaymentState = {
  products: [],
  transactions: [],
  wallet: null,
  isLoading: false,
  isInitialized: false,
  error: null,
  pendingPurchase: null,
};

function paymentReducer(state: PaymentState, action: PaymentAction): PaymentState {
  switch (action.type) {
    case 'SET_LOADING':
      return { ...state, isLoading: action.payload };
    case 'SET_INITIALIZED':
      return { ...state, isInitialized: action.payload };
    case 'SET_PRODUCTS':
      return { ...state, products: action.payload };
    case 'ADD_TRANSACTION':
      return { ...state, transactions: [action.payload, ...state.transactions] };
    case 'UPDATE_TRANSACTION':
      return {
        ...state,
        transactions: state.transactions.map((t) =>
          t.id === action.payload.id ? { ...t, ...action.payload.updates } : t
        ),
      };
    case 'SET_WALLET':
      return { ...state, wallet: action.payload };
    case 'SET_ERROR':
      return { ...state, error: action.payload, isLoading: false };
    case 'SET_PENDING_PURCHASE':
      return { ...state, pendingPurchase: action.payload };
    case 'CLEAR_ERROR':
      return { ...state, error: null };
    default:
      return state;
  }
}

interface PaymentContextType {
  state: PaymentState;
  initialize: () => Promise<void>;
  fetchProducts: (productIds: string[]) => Promise<Product[]>;
  purchaseProduct: (productId: string) => Promise<Transaction>;
  purchaseSubscription: (productId: string) => Promise<Transaction>;
  restorePurchases: () => Promise<Transaction[]>;
  processWalletPayment: (amount: number, currency: string, metadata?: Record<string, any>) => Promise<Transaction>;
  addPaymentCard: (cardData: CardInputData) => Promise<PaymentCard>;
  removePaymentCard: (cardId: string) => Promise<void>;
  setDefaultCard: (cardId: string) => Promise<void>;
  getTransactionHistory: () => Promise<Transaction[]>;
  refundTransaction: (transactionId: string) => Promise<Transaction>;
  validateReceipt: (receipt: string, provider: string) => Promise<boolean>;
  clearError: () => void;
}

export interface CardInputData {
  number: string;
  expiryMonth: number;
  expiryYear: number;
  cvv: string;
  holderName: string;
}

const PaymentContext = createContext<PaymentContextType | undefined>(undefined);

export const usePayment = (): PaymentContextType => {
  const context = useContext(PaymentContext);
  if (!context) {
    throw new Error('usePayment must be used within a PaymentProvider');
  }
  return context;
};

