// 2. payment/SecurityManager.ts - Encryption & Security Layer
// ============================================================

class SecurityManager {
  private encryptionKey: string;
  private static instance: SecurityManager;

  private constructor() {
    this.encryptionKey = '';
  }

  static getInstance(): SecurityManager {
    if (!SecurityManager.instance) {
      SecurityManager.instance = new SecurityManager();
    }
    return SecurityManager.instance;
  }

  async initialize(): Promise<void> {
    let storedKey = await AsyncStorage.getItem('@payment_enc_key');
    if (!storedKey) {
      storedKey = CryptoJS.lib.WordArray.random(256 / 8).toString();
      await AsyncStorage.setItem('@payment_enc_key', storedKey);
    }
    this.encryptionKey = storedKey;
  }

  encrypt(data: string): string {
    if (!this.encryptionKey) {
      throw new Error('SecurityManager not initialized');
    }
    const iv = CryptoJS.lib.WordArray.random(128 / 8);
    const encrypted = CryptoJS.AES.encrypt(data, CryptoJS.enc.Hex.parse(this.encryptionKey), {
      iv: iv,
      mode: CryptoJS.mode.CBC,
      padding: CryptoJS.pad.Pkcs7,
    });
    return iv.toString() + ':' + encrypted.toString();
  }

  decrypt(encryptedData: string): string {
    if (!this.encryptionKey) {
      throw new Error('SecurityManager not initialized');
    }
    const parts = encryptedData.split(':');
    const iv = CryptoJS.enc.Hex.parse(parts[0]);
    const encrypted = parts[1];
    const decrypted = CryptoJS.AES.decrypt(encrypted, CryptoJS.enc.Hex.parse(this.encryptionKey), {
      iv: iv,
      mode: CryptoJS.mode.CBC,
      padding: CryptoJS.pad.Pkcs7,
    });
    return decrypted.toString(CryptoJS.enc.Utf8);
  }

  hashData(data: string): string {
    return CryptoJS.SHA256(data).toString();
  }

  generateHMAC(data: string, secret: string): string {
    return CryptoJS.HmacSHA256(data, secret).toString();
  }

  sanitizeCardNumber(cardNumber: string): string {
    return cardNumber.replace(/\D/g, '');
  }

  maskCardNumber(cardNumber: string): string {
    const sanitized = this.sanitizeCardNumber(cardNumber);
    return '*'.repeat(sanitized.length - 4) + sanitized.slice(-4);
  }

  validateCardNumber(cardNumber: string): boolean {
    const sanitized = this.sanitizeCardNumber(cardNumber);
    if (sanitized.length < 13 || sanitized.length > 19) return false;

    // Luhn algorithm
    let sum = 0;
    let isEven = false;
    for (let i = sanitized.length - 1; i >= 0; i--) {
      let digit = parseInt(sanitized[i], 10);
      if (isEven) {
        digit *= 2;
        if (digit > 9) digit -= 9;
      }
      sum += digit;
      isEven = !isEven;
    }
    return sum % 10 === 0;
  }

  detectCardBrand(cardNumber: string): PaymentCard['brand'] {
    const sanitized = this.sanitizeCardNumber(cardNumber);
    if (/^4/.test(sanitized)) return 'visa';
    if (/^5[1-5]/.test(sanitized) || /^2[2-7]/.test(sanitized)) return 'mastercard';
    if (/^3[47]/.test(sanitized)) return 'amex';
    if (/^6(?:011|5)/.test(sanitized)) return 'discover';
    return 'visa'; // default
  }

  validateCVV(cvv: string, brand: PaymentCard['brand']): boolean {
    const length = brand === 'amex' ? 4 : 3;
    return /^\d+$/.test(cvv) && cvv.length === length;
  }

  validateExpiry(month: number, year: number): boolean {
    const now = new Date();
    const currentMonth = now.getMonth() + 1;
    const currentYear = now.getFullYear();
    if (year < currentYear) return false;
    if (year === currentYear && month < currentMonth) return false;
    return month >= 1 && month <= 12;
  }

  tokenizeCard(cardData: CardInputData): string {
    const payload = JSON.stringify({
      n: this.hashData(this.sanitizeCardNumber(cardData.number)),
      m: cardData.expiryMonth,
      y: cardData.expiryYear,
      t: Date.now(),
    });
    return this.encrypt(payload);
  }

  generateTransactionSignature(transaction: Partial<Transaction>): string {
    const payload = `${transaction.id}|${transaction.amount}|${transaction.currency}|${transaction.timestamp}`;
    return this.generateHMAC(payload, this.encryptionKey);
  }

  verifyTransactionSignature(transaction: Transaction, signature: string): boolean {
    const expectedSignature = this.generateTransactionSignature(transaction);
    return expectedSignature === signature;
  }
}

const securityManager = SecurityManager.getInstance();

