interface APIConfig {
  baseUrl: string;
  apiKey: string;
  timeout: number;
}

class PaymentAPIService {
  private config: APIConfig;
  private static instance: PaymentAPIService;

  private constructor() {
    this.config = {
      baseUrl: process.env.PAYMENT_API_URL || 'https://api.yourpaymentservice.com/v1',
      apiKey: process.env.PAYMENT_API_KEY || '',
      timeout: 30000,
    };
  }

  static getInstance(): PaymentAPIService {
    if (!PaymentAPIService.instance) {
      PaymentAPIService.instance = new PaymentAPIService();
    }
    return PaymentAPIService.instance;
  }

  configure(config: Partial<APIConfig>): void {
    this.config = { ...this.config, ...config };
  }

  private async request<T>(
    endpoint: string,
    method: 'GET' | 'POST' | 'PUT' | 'DELETE',
    body?: any,
    idempotencyKey?: string
  ): Promise<T> {
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), this.config.timeout);

    const headers: Record<string, string> = {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${this.config.apiKey}`,
      'X-Platform': Platform.OS,
      'X-Request-Id': uuidv4(),
    };

    if (idempotencyKey) {
      headers['Idempotency-Key'] = idempotencyKey;
    }

    try {
      const response = await fetch(`${this.config.baseUrl}${endpoint}`, {
        method,
        headers,
        body: body ? JSON.stringify(body) : undefined,
        signal: controller.signal,
      });

      clearTimeout(timeoutId);

      if (!response.ok) {
        const errorBody = await response.json().catch(() => ({}));
        throw new PaymentError(
          errorBody.message || `HTTP ${response.status}`,
          errorBody.code || 'API_ERROR',
          response.status
        );
      }

      return response.json();
    } catch (error: any) {
      clearTimeout(timeoutId);
      if (error.name === 'AbortError') {
        throw new PaymentError('Request timeout', 'TIMEOUT', 408);
      }
      if (error instanceof PaymentError) throw error;
      throw new PaymentError(error.message, 'NETWORK_ERROR', 0);
    }
  }

  async validateReceipt(receipt: string, provider: string): Promise<{ valid: boolean; expiresAt?: number }> {
    return this.request('/receipts/validate', 'POST', { receipt, provider, platform: Platform.OS });
  }

  async createPaymentIntent(
    amount: number,
    currency: string,
    paymentMethodId: string,
    metadata?: Record<string, any>
  ): Promise<{ clientSecret: string; intentId: string }> {
    const idempotencyKey = uuidv4();
    return this.request(
      '/payment-intents',
      'POST',
      { amount, currency, paymentMethodId, metadata },
      idempotencyKey
    );
  }

  async confirmPayment(intentId: string): Promise<{ status: string; transactionId: string }> {
    return this.request(`/payment-intents/${intentId}/confirm`, 'POST');
  }

  async tokenizeCard(encryptedCardData: string): Promise<{ tokenId: string; last4: string; brand: string }> {
    return this.request('/tokens', 'POST', { encryptedCard: encryptedCardData });
  }

  async getWallet(): Promise<WalletInfo> {
    return this.request('/wallet', 'GET');
  }

  async addCardToWallet(tokenId: string): Promise<PaymentCard> {
    return this.request('/wallet/cards', 'POST', { tokenId });
  }

  async removeCardFromWallet(cardId: string): Promise<void> {
    return this.request(`/wallet/cards/${cardId}`, 'DELETE');
  }

  async setDefaultCard(cardId: string): Promise<void> {
    return this.request(`/wallet/cards/${cardId}/default`, 'PUT');
  }

  async getTransactions(page: number = 1, limit: number = 50): Promise<Transaction[]> {
    return this.request(`/transactions?page=${page}&limit=${limit}`, 'GET');
  }

  async requestRefund(transactionId: string, reason?: string): Promise<Transaction> {
    return this.request(`/transactions/${transactionId}/refund`, 'POST', { reason });
  }

  async processWalletPayment(
    amount: number,
    currency: string,
    cardId: string,
    metadata?: Record<string, any>
  ): Promise<Transaction> {
    const idempotencyKey = uuidv4();
    return this.request(
      '/wallet/pay',
      'POST',
      { amount, currency, cardId, metadata },
      idempotencyKey
    );
  }
}

const paymentAPI = PaymentAPIService.getInstance();

