// 4. payment/PaymentError.ts - Custom Error Class
// ============================================================

class PaymentError extends Error {
  code: string;
  statusCode: number;
  isRetryable: boolean;

  constructor(message: string, code: string, statusCode: number) {
    super(message);
    this.name = 'PaymentError';
    this.code = code;
    this.statusCode = statusCode;
    this.isRetryable = [408, 429, 500, 502, 503, 504].includes(statusCode);
  }
}

// ============================================================
// 5. payment/IAPManager.ts - In-App Purchase Manager
// ============================================================

class IAPManager {
  private purchaseUpdateSubscription: any = null;
  private purchaseErrorSubscription: any = null;
  private onPurchaseUpdate: ((purchase: RNIap.Purchase) => void) | null = null;
  private onPurchaseError: ((error: RNIap.PurchaseError) => void) | null = null;

  async initialize(): Promise<void> {
    try {
      await RNIap.initConnection();

      if (Platform.OS === 'android') {
        await RNIap.flushFailedPurchasesCachedAsPendingAndroid();
      }
    } catch (error: any) {
      throw new PaymentError(
        `IAP initialization failed: ${error.message}`,
        'IAP_INIT_FAILED',
        0
      );
    }
  }

  setupListeners(
    onUpdate: (purchase: RNIap.Purchase) => void,
    onError: (error: RNIap.PurchaseError) => void
  ): void {
    this.onPurchaseUpdate = onUpdate;
    this.onPurchaseError = onError;

    this.purchaseUpdateSubscription = RNIap.purchaseUpdatedListener(
      (purchase: RNIap.InAppPurchase | RNIap.SubscriptionPurchase) => {
        if (this.onPurchaseUpdate) {
          this.onPurchaseUpdate(purchase as RNIap.Purchase);
        }
      }
    );

    this.purchaseErrorSubscription = RNIap.purchaseErrorListener(
      (error: RNIap.PurchaseError) => {
        if (this.onPurchaseError) {
          this.onPurchaseError(error);
        }
      }
    );
  }

  async getProducts(productIds: string[]): Promise<RNIap.Product[]> {
    try {
      const products = await RNIap.getProducts({ skus: productIds });
      return products;
    } catch (error: any) {
      throw new PaymentError(
        `Failed to fetch products: ${error.message}`,
        'FETCH_PRODUCTS_FAILED',
        0
      );
    }
  }

  async getSubscriptions(subscriptionIds: string[]): Promise<RNIap.Subscription[]> {
    try {
      const subscriptions = await RNIap.getSubscriptions({ skus: subscriptionIds });
      return subscriptions;
    } catch (error: any) {
      throw new PaymentError(
        `Failed to fetch subscriptions: ${error.message}`,
        'FETCH_SUBSCRIPTIONS_FAILED',
        0
      );
    }
  }

  async requestPurchase(productId: string): Promise<void> {
    try {
      await RNIap.requestPurchase({ sku: productId });
    } catch (error: any) {
      if (error.code === 'E_USER_CANCELLED') {
        throw new PaymentError('Purchase cancelled by user', 'USER_CANCELLED', 0);
      }
      throw new PaymentError(
        `Purchase failed: ${error.message}`,
        'PURCHASE_FAILED',
        0
      );
    }
  }

  async requestSubscription(productId: string): Promise<void> {
    try {
      await RNIap.requestSubscription({ sku: productId });
    } catch (error: any) {
      if (error.code === 'E_USER_CANCELLED') {
        throw new PaymentError('Subscription cancelled by user', 'USER_CANCELLED', 0);
      }
      throw new PaymentError(
        `Subscription failed: ${error.message}`,
        'SUBSCRIPTION_FAILED',
        0
      );
    }
  }

  async finishTransaction(purchase: RNIap.Purchase, isConsumable: boolean = false): Promise<void> {
    try {
      if (Platform.OS === 'ios') {
        await RNIap.finishTransaction({ purchase, isConsumable });
      } else {
        if (isConsumable) {
          await RNIap.consumePurchaseAndroid({ token: purchase.purchaseToken! });
        } else {
          await RNIap.acknowledgePurchaseAndroid({ token: purchase.purchaseToken! });
        }
      }
    } catch (error: any) {
      throw new PaymentError(
        `Failed to finish transaction: ${error.message}`,
        'FINISH_TRANSACTION_FAILED',
        0
      );
    }
  }

  async getAvailablePurchases(): Promise<RNIap.Purchase[]> {
    try {
      return await RNIap.getAvailablePurchases();
    } catch (error: any) {
      throw new PaymentError(
        `Failed to restore purchases: ${error.message}`,
        'RESTORE_FAILED',
        0
      );
    }
  }

  cleanup(): void {
    if (this.purchaseUpdateSubscription) {
      this.purchaseUpdateSubscription.remove();
      this.purchaseUpdateSubscription = null;
    }
    if (this.purchaseErrorSubscription) {
      this.purchaseErrorSubscription.remove();
      this.purchaseErrorSubscription = null;
    }
    RNIap.endConnection();
  }
}

