// 6. payment/TransactionStore.ts - Local Transaction Persistence
// ============================================================

class TransactionStore {
  private static STORAGE_KEY = '@payment_transactions';
  private static MAX_LOCAL_TRANSACTIONS = 200;

  static async saveTransaction(transaction: Transaction): Promise<void> {
    try {
      const encrypted = securityManager.encrypt(JSON.stringify(transaction));
      const existing = await this.getStoredTransactions();
      const updated = [encrypted, ...existing].slice(0, this.MAX_LOCAL_TRANSACTIONS);
      await AsyncStorage.setItem(this.STORAGE_KEY, JSON.stringify(updated));
    } catch (error) {
      console.error('Failed to save transaction locally:', error);
    }
  }

  static async getStoredTransactions(): Promise<string[]> {
    try {
      const data = await AsyncStorage.getItem(this.STORAGE_KEY);
      return data ? JSON.parse(data) : [];
    } catch {
      return [];
    }
  }

  static async getDecryptedTransactions(): Promise<Transaction[]> {
    const stored = await this.getStoredTransactions();
    return stored
      .map((encrypted) => {
        try {
          return JSON.parse(securityManager.decrypt(encrypted));
        } catch {
          return null;
        }
      })
      .filter(Boolean) as Transaction[];
  }

  static async updateTransaction(id: string, updates: Partial<Transaction>): Promise<void> {
    const transactions = await this.getDecryptedTransactions();
    const updated = transactions.map((t) => (t.id === id ? { ...t, ...updates } : t));
    const encrypted = updated.map((t) => securityManager.encrypt(JSON.stringify(t)));
    await AsyncStorage.setItem(this.STORAGE_KEY, JSON.stringify(encrypted));
  }

  static async clearAll(): Promise<void> {
    await AsyncStorage.removeItem(this.STORAGE_KEY);
  }
}

// ============================================================
// 7. payment/RetryManager.ts - Retry Logic for Failed Operations
// ============================================================

class RetryManager {
  static async withRetry<T>(
    operation: () => Promise<T>,
    maxRetries: number = 3,
    baseDelay: number = 1000,
    onRetry?: (attempt: number, error: Error) => void
  ): Promise<T> {
    let lastError: Error | null = null;

    for (let attempt = 0; attempt <= maxRetries; attempt++) {
      try {
        return await operation();
      } catch (error: any) {
        lastError = error;

        if (error instanceof PaymentError && !error.isRetryable) {
          throw error;
        }

        if (attempt < maxRetries) {
          const delay = baseDelay * Math.pow(2, attempt) + Math.random() * 1000;
          onRetry?.(attempt + 1, error);
          await new Promise((resolve) => setTimeout(resolve, delay));
        }
      }
    }

    throw lastError || new Error('Max retries exceeded');
  }
}

// ============================================================
// 8. PaymentProvider Component
// ============================================================

interface PaymentProviderProps {
  children: React.ReactNode;
  apiConfig?: Partial<APIConfig>;
  productIds?: string[];
  subscriptionIds?: string[];
}

export const PaymentProvider: React.FC<PaymentProviderProps> = ({
  children,
  apiConfig,
  productIds = [],
  subscriptionIds = [],
}) => {
  const [state, dispatch] = useReducer(paymentReducer, initialState);
  const iapManager = useRef(new IAPManager()).current;
  const isInitializing = useRef(false);

  // Initialize the payment system
  const initialize = useCallback(async () => {
    if (isInitializing.current || state.isInitialized) return;
    isInitializing.current = true;

    dispatch({ type: 'SET_LOADING', payload: true });

    try {
      // Initialize security
      await securityManager.initialize();

      // Configure API
      if (apiConfig) {
        paymentAPI.configure(apiConfig);
      }

      // Initialize IAP
      await iapManager.initialize();

      // Setup IAP listeners
      iapManager.setupListeners(
        async (purchase: RNIap.Purchase) => {
          await handlePurchaseUpdate(purchase);
        },
        (error: RNIap.PurchaseError) => {
          handlePurchaseError(error);
        }
      );

      // Load wallet info
      try {
        const wallet = await paymentAPI.getWallet();
        dispatch({ type: 'SET_WALLET', payload: wallet });
      } catch {
        // Wallet may not exist yet
      }

      // Load cached transactions
      const cachedTransactions = await TransactionStore.getDecryptedTransactions();
      cachedTransactions.forEach((t) => {
        dispatch({ type: 'ADD_TRANSACTION', payload: t });
      });

      dispatch({ type: 'SET_INITIALIZED', payload: true });
      dispatch({ type: 'SET_LOADING', payload: false });
    } catch (error: any) {
      dispatch({ type: 'SET_ERROR', payload: error.message });
    } finally {
      isInitializing.current = false;
    }
  }, [apiConfig, state.isInitialized]);

  // Cleanup
  useEffect(() => {
    return () => {
      iapManager.cleanup();
    };
  }, []);

  // Handle purchase updates from IAP
  const handlePurchaseUpdate = async (purchase: RNIap.Purchase) => {
    const receipt = Platform.OS === 'ios'
      ? purchase.transactionReceipt
      : purchase.purchaseToken;

    if (!receipt) return;

    const transaction: Transaction = {
      id: uuidv4(),
      productId: purchase.productId,
      amount: 0, // Will be resolved from product info
      currency: 'USD',
      status: 'pending',
      provider: Platform.OS === 'ios' ? 'apple' : 'google',
      receipt: receipt,
      timestamp: Date.now(),
      idempotencyKey: uuidv4(),
    };

    dispatch({ type: 'ADD_TRANSACTION', payload: transaction });
    dispatch({ type: 'SET_PENDING_PURCHASE', payload: null });

    try {
      // Validate receipt server-side
      const validation = await RetryManager.withRetry(
        () => paymentAPI.validateReceipt(receipt, Platform.OS),
        3
      );

      if (validation.valid) {
        // Finish the transaction
        await iapManager.finishTransaction(purchase, true);

        const updates: Partial<Transaction> = { status: 'completed' };
        dispatch({ type: 'UPDATE_TRANSACTION', payload: { id: transaction.id, updates } });
        await TransactionStore.saveTransaction({ ...transaction, ...updates });
      } else {
        const updates: Partial<Transaction> = { status: 'failed' };
        dispatch({ type: 'UPDATE_TRANSACTION', payload: { id: transaction.id, updates } });
        await TransactionStore.saveTransaction({ ...transaction, ...updates });
      }
    } catch (error: any) {
      const updates: Partial<Transaction> = { status: 'failed' };
      dispatch({ type: 'UPDATE_TRANSACTION', payload: { id: transaction.id, updates } });
      dispatch({ type: 'SET_ERROR', payload: error.message });
    }
  };

  const handlePurchaseError = (error: RNIap.PurchaseError) => {
    dispatch({ type: 'SET_PENDING_PURCHASE', payload: null });
    if (error.code !== 'E_USER_CANCELLED') {
      dispatch({ type: 'SET_ERROR', payload: error.message || 'Purchase failed' });
    }
  };

  // Fetch available products
  const fetchProducts = useCallback(
    async (ids: string[]): Promise<Product[]> => {
      dispatch({ type: 'SET_LOADING', payload: true });
      try {
        const iapProducts = await iapManager.getProducts(ids);
        const products: Product[] = iapProducts.map((p) => ({
          productId: p.productId,
          title: p.title,
          description: p.description,
          price: p.price,
          currency: p.currency,
          localizedPrice: p.localizedPrice,
          type: 'inapp' as const,
        }));

        dispatch({ type: 'SET_PRODUCTS', payload: products });
        dispatch({ type: 'SET_LOADING', payload: false });
        return products;
      } catch (error: any) {
        dispatch({ type: 'SET_ERROR', payload: error.message });
        return [];
      }
    },
    []
  );

  // Purchase a product
  const purchaseProduct = useCallback(
    async (productId: string): Promise<Transaction> => {
      if (state.pendingPurchase) {
        throw new PaymentError('A purchase is already in progress', 'PURCHASE_IN_PROGRESS', 0);
      }

      dispatch({ type: 'SET_PENDING_PURCHASE', payload: productId });
      dispatch({ type: 'SET_LOADING', payload: true });

      try {
        await iapManager.requestPurchase(productId);

        // The actual transaction handling happens in the purchase listener
        // Return a pending transaction
        return {
          id: uuidv4(),
          productId,
          amount: 0,
          currency: 'USD',
          status: 'pending',
          provider: Platform.OS === 'ios' ? 'apple' : 'google',
          timestamp: Date.now(),
          idempotencyKey: uuidv4(),
        };
      } catch (error: any) {
        dispatch({ type: 'SET_PENDING_PURCHASE', payload: null });
        dispatch({ type: 'SET_LOADING', payload: false });
        throw error;
      }
    },
    [state.pendingPurchase]
  );

  // Purchase a subscription
  const purchaseSubscription = useCallback(
    async (productId: string): Promise<Transaction> => {
      if (state.pendingPurchase) {
        throw new PaymentError('A purchase is already in progress', 'PURCHASE_IN_PROGRESS', 0);
      }

      dispatch({ type: 'SET_PENDING_PURCHASE', payload: productId });
      dispatch({ type: 'SET_LOADING', payload: true });

      try {
        await iapManager.requestSubscription(productId);
        return {
          id: uuidv4(),
          productId,
          amount: 0,
          currency: 'USD',
          status: 'pending',
          provider: Platform.OS === 'ios' ? 'apple' : 'google',
          timestamp: Date.now(),
          idempotencyKey: uuidv4(),
        };
      } catch (error: any) {
        dispatch({ type: 'SET_PENDING_PURCHASE', payload: null });
        dispatch({ type: 'SET_LOADING', payload: false });
        throw error;
      }
    },
    [state.pendingPurchase]
  );

  // Restore purchases
  const restorePurchases = useCallback(async (): Promise<Transaction[]> => {
    dispatch({ type: 'SET_LOADING', payload: true });
    try {
      const purchases = await iapManager.getAvailablePurchases();
      const transactions: Transaction[] = purchases.map((p) => ({
        id: uuidv4(),
        productId: p.productId,
        amount: 0,
        currency: 'USD',
        status: 'completed' as const,
        provider: (Platform.OS === 'ios' ? 'apple' : 'google') as 'apple' | 'google',
        receipt: Platform.OS === 'ios' ? p.transactionReceipt : p.purchaseToken,
        timestamp: p.transactionDate ? new Date(p.transactionDate).getTime() : Date.now(),
        idempotencyKey: uuidv4(),
      }));

      transactions.forEach((t) => {
        dispatch({ type: 'ADD_TRANSACTION', payload: t });
      });

      dispatch({ type: 'SET_LOADING', payload: false });
      return transactions;
    } catch (error: any) {
      dispatch({ type: 'SET_ERROR', payload: error.message });
      return [];
    }
  }, []);

  // Process wallet/card payment
  const processWalletPayment = useCallback(
    async (
      amount: number,
      currency: string,
      metadata?: Record<string, any>
    ): Promise<Transaction> => {
      if (!state.wallet || state.wallet.cards.length === 0) {
        throw new PaymentError('No payment method available', 'NO_PAYMENT_METHOD', 0);
      }

      dispatch({ type: 'SET_LOADING', payload: true });

      const defaultCard = state.wallet.cards.find((c) => c.isDefault) || state.wallet.cards[0];

      try {
        const transaction = await RetryManager.withRetry(
          () => paymentAPI.processWalletPayment(amount, currency, defaultCard.id, metadata),
          2
        );

        dispatch({ type: 'ADD_TRANSACTION', payload: transaction });
        await TransactionStore.saveTransaction(transaction);
        dispatch({ type: 'SET_LOADING', payload: false });
        return transaction;
      } catch (error: any) {
        const failedTransaction: Transaction = {
          id: uuidv4(),
          productId: '',
          amount,
          currency,
          status: 'failed',
          provider: 'wallet',
          timestamp: Date.now(),
          metadata,
          idempotencyKey: uuidv4(),
        };
        dispatch({ type: 'ADD_TRANSACTION', payload: failedTransaction });
        dispatch({ type: 'SET_ERROR', payload: error.message });
        throw error;
      }
    },
    [state.wallet]
  );

  // Add payment card
  const addPaymentCard = useCallback(async (cardData: CardInputData): Promise<PaymentCard> => {
    dispatch({ type: 'SET_LOADING', payload: true });

    // Validate card data
    if (!securityManager.validateCardNumber(cardData.number)) {
      dispatch({ type: 'SET_ERROR', payload: 'Invalid card number' });
      throw new PaymentError('Invalid card number', 'INVALID_CARD', 0);
    }

    const brand = securityManager.detectCardBrand(cardData.number);

    if (!securityManager.validateCVV(cardData.cvv, brand)) {
      dispatch({ type: 'SET_ERROR', payload: 'Invalid CVV' });
      throw new PaymentError('Invalid CVV', 'INVALID_CVV', 0);
    }

    if (!securityManager.validateExpiry(cardData.expiryMonth, cardData.expiryYear)) {
      dispatch({ type: 'SET_ERROR', payload: 'Card expired' });
      throw new PaymentError('Card expired', 'CARD_EXPIRED', 0);
    }

    try {
      // Tokenize locally first
      const tokenizedData = securityManager.tokenizeCard(cardData);

      // Send to server for tokenization
      const tokenResult = await paymentAPI.tokenizeCard(tokenizedData);

      // Add to wallet
      const card = await paymentAPI.addCardToWallet(tokenResult.tokenId);

      // Update local wallet state
      if (state.wallet) {
        const updatedWallet: WalletInfo = {
          ...state.wallet,
          cards: [...state.wallet.cards, card],
          lastUpdated: Date.now(),
        };
        dispatch({ type: 'SET_WALLET', payload: updatedWallet });
      }

      dispatch({ type: 'SET_LOADING', payload: false });
      return card;
    } catch (error: any) {
      dispatch({ type: 'SET_ERROR', payload: error.message });
      throw error;
    }
  }, [state.wallet]);

  // Remove payment card
  const removePaymentCard = useCallback(
    async (cardId: string): Promise<void> => {
      dispatch({ type: 'SET_LOADING', payload: true });
      try {
        await paymentAPI.removeCardFromWallet(cardId);

        if (state.wallet) {
          const updatedWallet: WalletInfo = {
            ...state.wallet,
            cards: state.wallet.cards.filter((c) => c.id !== cardId),
            lastUpdated: Date.now(),
          };
          dispatch({ type: 'SET_WALLET', payload: updatedWallet });
        }

        dispatch({ type: 'SET_LOADING', payload: false });
      } catch (error: any) {
        dispatch({ type: 'SET_ERROR', payload: error.message });
        throw error;
      }
    },
    [state.wallet]
  );

  // Set default card
  const setDefaultCard = useCallback(
    async (cardId: string): Promise<void> => {
      try {
        await paymentAPI.setDefaultCard(cardId);

        if (state.wallet) {
          const updatedWallet: WalletInfo = {
            ...state.wallet,
            cards: state.wallet.cards.map((c) => ({
              ...c,
              isDefault: c.id === cardId,
            })),
            lastUpdated: Date.now(),
          };
          dispatch({ type: 'SET_WALLET', payload: updatedWallet });
        }
      } catch (error: any) {
        dispatch({ type: 'SET_ERROR', payload: error.message });
        throw error;
      }
    },
    [state.wallet]
  );

  // Get transaction history
  const getTransactionHistory = useCallback(async (): Promise<Transaction[]> => {
    try {
      const transactions = await paymentAPI.getTransactions();
      return transactions;
    } catch {
      // Fall back to local cache
      return TransactionStore.getDecryptedTransactions();
    }
  }, []);

  // Refund transaction
  const refundTransaction = useCallback(
    async (transactionId: string): Promise<Transaction> => {
      dispatch({ type: 'SET_LOADING', payload: true });
      try {
        const refunded = await paymentAPI.requestRefund(transactionId);
        dispatch({
          type: 'UPDATE_TRANSACTION',
          payload: { id: transactionId, updates: { status: 'refunded' } },
        });
        dispatch({ type: 'SET_LOADING', payload: false });
        return refunded;
      } catch (error: any) {
        dispatch({ type: 'SET_ERROR', payload: error.message });
        throw error;
      }
    },
    []
  );

  // Validate receipt
  const validateReceipt = useCallback(
    async (receipt: string, provider: string): Promise<boolean> => {
      try {
        const result = await RetryManager.withRetry(
          () => paymentAPI.validateReceipt(receipt, provider),
          3
        );
        return result.valid;
      } catch {
        return false;
      }
    },
    []
  );

  const clearError = useCallback(() => {
    dispatch({ type: 'CLEAR_ERROR' });
  }, []);

  const contextValue: PaymentContextType = {
    state,
    initialize,
    fetchProducts,
    purchaseProduct,
    purchaseSubscription,
    restorePurchases,
    processWalletPayment,
    addPaymentCard,
    removePaymentCard,
    setDefaultCard,
    getTransactionHistory,
    refundTransaction,
    validateReceipt,
    clearError,
  };

  return (
    <PaymentContext.Provider value={contextValue}>
      {children}
    </PaymentContext.Provider>
  );
};

// ============================================================
// 9. components/ProductList.tsx - Product Display Component
// ============================================================

import { View, Text, FlatList, TouchableOpacity, StyleSheet, ActivityIndicator } from 'react-native';

export const ProductList: React.FC<{
  onPurchase?: (product: Product) => void;
}> = ({ onPurchase }) => {
  const { state, purchaseProduct, purchaseSubscription } = usePayment();

  const handlePurchase = async (product: Product) => {
    try {
      if (product.type === 'subscription') {
        await purchaseSubscription(product.productId);
      } else {
        await purchaseProduct(product.productId);
      }
      onPurchase?.(product);
    } catch (error: any) {
      if (error.code !== 'USER_CANCELLED') {
        Alert.alert('Purchase Failed', error.message);
      }
    }
  };

  const renderProduct = ({ item }: { item: Product }) => (
    <View style={styles.productCard}>
      <View style={styles.productInfo}>
        <Text style={styles.productTitle}>{item.title}</Text>
        <Text style={styles.productDescription}>{item.description}</Text>
        <Text style={styles.productPrice}>{item.localizedPrice}</Text>
      </View>
      <TouchableOpacity
        style={[
          styles.purchaseButton,
          state.pendingPurchase === item.productId && styles.purchaseButtonDisabled,
        ]}
        onPress={() => handlePurchase(item)}
        disabled={!!state.pendingPurchase}
      >
        {state.pendingPurchase === item.productId ? (
          <ActivityIndicator color="#fff" />
        ) : (
          <Text style={styles.purchaseButtonText}>
            {item.type === 'subscription' ? 'Subscribe' : 'Buy'}
          </Text>
        )}
      </TouchableOpacity>
    </View>
  );

  if (state.isLoading && state.products.length === 0) {
    return (
      <View style={styles.centered}>
        <ActivityIndicator size="large" color="#007AFF" />
      </View>
    );
  }

  return (
    <FlatList
      data={state.products}
      renderItem={renderProduct}
      keyExtractor={(item) => item.productId}
      contentContainerStyle={styles.productList}
      ListEmptyComponent={
        <View style={styles.centered}>
          <Text style={styles.emptyText}>No products available</Text>
        </View>
      }
    />
  );
};

// ============================================================
// 10. components/CardInput.tsx - Secure Card Input Component
// ============================================================

import { TextInput } from 'react-native';

interface CardInputState {
  number: string;
  expiryMonth: string;
  expiryYear: string;
  cvv: string;
  holderName: string;
  errors: Record<string, string>;
}

export const CardInput: React.FC<{
  onSubmit: (card: PaymentCard) => void;
  onCancel?: () => void;
}> = ({ onSubmit, onCancel }) => {
  const { addPaymentCard, state } = usePayment();
  const [cardState, setCardState] = React.useState<CardInputState>({
    number: '',
    expiryMonth: '',
    expiryYear: '',
    cvv: '',
    holderName: '',
    errors: {},
  });

  const formatCardNumber = (text: string): string => {
    const cleaned = text.replace(/\D/g, '').substring(0, 19);
    const groups = cleaned.match(/.{1,4}/g);
    return groups ? groups.join(' ') : '';
  };

  const handleCardNumberChange = (text: string) => {
    const formatted = formatCardNumber(text);
    setCardState((prev) => ({
      ...prev,
      number: formatted,
      errors: { ...prev.errors, number: '' },
    }));
  };

  const handleExpiryChange = (text: string) => {
    const cleaned = text.replace(/\D/g, '').substring(0, 4);
    let month = '';
    let year = '';
    if (cleaned.length >= 2) {
      month = cleaned.substring(0, 2);
      year = cleaned.substring(2);
    } else {
      month = cleaned;
    }
    setCardState((prev) => ({
      ...prev,
      expiryMonth: month,
      expiryYear: year,
      errors: { ...prev.errors, expiry: '' },
    }));
  };

  const getExpiryDisplay = (): string => {
    if (cardState.expiryMonth && cardState.expiryYear) {
      return `${cardState.expiryMonth}/${cardState.expiryYear}`;
    }
    if (cardState.expiryMonth) {
      return cardState.expiryMonth;
    }
    return '';
  };

  const validate = (): boolean => {
    const errors: Record<string, string> = {};
    const sm = SecurityManager.getInstance();
    const rawNumber = cardState.number.replace(/\s/g, '');

    if (!sm.validateCardNumber(rawNumber)) {
      errors.number = 'Invalid card number';
    }

    const month = parseInt(cardState.expiryMonth, 10);
    const year = parseInt(`20${cardState.expiryYear}`, 10);
    if (!sm.validateExpiry(month, year)) {
      errors.expiry = 'Invalid or expired date';
    }

    const brand = sm.detectCardBrand(rawNumber);
    if (!sm.validateCVV(cardState.cvv, brand)) {
      errors.cvv = 'Invalid CVV';
    }

    if (!cardState.holderName.trim()) {
      errors.holderName = 'Name is required';
    }

    setCardState((prev) => ({ ...prev, errors }));
    return Object.keys(errors).length === 0;
  };

  const handleSubmit = async () => {
    if (!validate()) return;

    try {
      const card = await addPaymentCard({
        number: cardState.number.replace(/\s/g, ''),
        expiryMonth: parseInt(cardState.expiryMonth, 10),
        expiryYear: parseInt(`20${cardState.expiryYear}`, 10),
        cvv: cardState.cvv,
        holderName: cardState.holderName,
      });

      // Clear sensitive data immediately
      setCardState({
        number: '',
        expiryMonth: '',
        expiryYear: '',
        cvv: '',
        holderName: '',
        errors: {},
      });

      onSubmit(card);
    } catch (error: any) {
      Alert.alert('Error', error.message);
    }
  };

  return (
    <View style={styles.cardInputContainer}>
      <Text style={styles.cardInputTitle}>Add Payment Card</Text>

      <View style={styles.inputGroup}>
        <Text style={styles.inputLabel}>Card Number</Text>
        <TextInput
          style={[styles.input, cardState.errors.number ? styles.inputError : null]}
          placeholder="4242 4242 4242 4242"
          value={cardState.number}
          onChangeText={handleCardNumberChange}
          keyboardType="number-pad"
          maxLength={23}
          secureTextEntry={false}
          autoComplete="cc-number"
          textContentType="creditCardNumber"
        />
        {cardState.errors.number && (
          <Text style={styles.errorText}>{cardState.errors.number}</Text>
        )}
      </View>

      <View style={styles.inputRow}>
        <View style={[styles.inputGroup, { flex: 1, marginRight: 8 }]}>
          <Text style={styles.inputLabel}>Expiry</Text>
          <TextInput
            style={[styles.input, cardState.errors.expiry ? styles.inputError : null]}
            placeholder="MM/YY"
            value={getExpiryDisplay()}
            onChangeText={handleExpiryChange}
            keyboardType="number-pad"
            maxLength={5}
          />
          {cardState.errors.expiry && (
            <Text style={styles.errorText}>{cardState.errors.expiry}</Text>
          )}
        </View>

        <View style={[styles.inputGroup, { flex: 1, marginLeft: 8 }]}>
          <Text style={styles.inputLabel}>CVV</Text>
          <TextInput
            style={[styles.input, cardState.errors.cvv ? styles.inputError : null]}
            placeholder="123"
            value={cardState.cvv}
            onChangeText={(text) =>
              setCardState((prev) => ({
                ...prev,
                cvv: text.replace(/\D/g, '').substring(0, 4),
                errors: { ...prev.errors, cvv: '' },
              }))
            }
            keyboardType="number-pad"
            maxLength={4}
            secureTextEntry={true}
          />
          {cardState.errors.cvv && (
            <Text style={styles.errorText}>{cardState.errors.cvv}</Text>
          )}
        </View>
      </View>

      <View style={styles.inputGroup}>
        <Text style={styles.inputLabel}>Cardholder Name</Text>
        <TextInput
          style={[styles.input, cardState.errors.holderName ? styles.inputError : null]}
          placeholder="John Doe"
          value={cardState.holderName}
          onChangeText={(text) =>
            setCardState((prev) => ({
              ...prev,
              holderName: text,
              errors: { ...prev.errors, holderName: '' },
            }))
          }
          autoCapitalize="words"
          autoComplete="cc-name"
        />
        {cardState.errors.holderName && (
          <Text style={styles.errorText}>{cardState.errors.holderName}</Text>
        )}
      </View>

      <View style={styles.buttonRow}>
        {onCancel && (
          <TouchableOpacity style={styles.cancelButton} onPress={onCancel}>
            <Text style={styles.cancelButtonText}>Cancel</Text>
          </TouchableOpacity>
        )}
        <TouchableOpacity
          style={[styles.submitButton, state.isLoading && styles.submitButtonDisabled]}
          onPress={handleSubmit}
          disabled={state.isLoading}
        >
          {state.isLoading ? (
            <ActivityIndicator color="#fff" />
          ) : (
            <Text style={styles.submitButtonText}>Add Card</Text>
          )}
        </TouchableOpacity>
      </View>
    </View>
  );
};

